// Calcular costes acumulados por herramienta en el mes actual
const rows = $input.first().json.values || [];
const now = new Date();
const currentMonth = now.getMonth();
const currentYear = now.getFullYear();

// Topes mensuales configurables (€)
const BUDGET_CAPS = {
  'retell_ai': { cap: 50, warn_pct: 70, cut_pct: 90, name: 'Retell AI' },
  'hetzner_gpu': { cap: 98, warn_pct: 80, cut_pct: 95, name: 'Hetzner GPU' },
  'n8n_cloud': { cap: 20, warn_pct: 75, cut_pct: 90, name: 'n8n Cloud' },
  'microsoft_graph': { cap: 12, warn_pct: 70, cut_pct: 90, name: 'Microsoft Graph' },
  'cal_com': { cap: 12, warn_pct: 70, cut_pct: 90, name: 'Cal.com' },
  'supabase': { cap: 25, warn_pct: 70, cut_pct: 90, name: 'Supabase' },
  'otros': { cap: 50, warn_pct: 80, cut_pct: 95, name: 'Otros' }
};

const accumulated = {};

for (const row of rows) {
  const [dateStr, tool, , amount] = row;
  const date = new Date(dateStr);
  if (date.getMonth() !== currentMonth || date.getFullYear() !== currentYear) continue;

  const toolKey = (tool || 'otros').toLowerCase().replace(/[\s.]/g, '_');
  if (!accumulated[toolKey]) accumulated[toolKey] = 0;
  accumulated[toolKey] += parseFloat(amount) || 0;
}

// Evaluar guardrails
const alerts = [];
let totalSpent = 0;
let totalCap = 0;

for (const [toolKey, config] of Object.entries(BUDGET_CAPS)) {
  const spent = accumulated[toolKey] || 0;
  totalSpent += spent;
  totalCap += config.cap;
  const pct = config.cap > 0 ? (spent / config.cap * 100) : 0;

  if (pct >= config.cut_pct) {
    alerts.push({
      tool: config.name,
      level: '🔴 CORTE',
      spent: spent.toFixed(2),
      cap: config.cap,
      pct: pct.toFixed(1)
    });
  } else if (pct >= config.warn_pct) {
    alerts.push({
      tool: config.name,
      level: '🟡 AVISO',
      spent: spent.toFixed(2),
      cap: config.cap,
      pct: pct.toFixed(1)
    });
  }
}

const totalPct = totalCap > 0 ? (totalSpent / totalCap * 100) : 0;

return [{
  json: {
    alerts,
    has_alerts: alerts.length > 0,
    total_spent: totalSpent.toFixed(2),
    total_cap: totalCap,
    total_pct: totalPct.toFixed(1),
    accumulated,
    month: `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}`,
    evaluated_at: now.toISOString()
  }
}];

const data = $input.first().json;
const alerts = data.alerts;

let message = `⚠️ <b>Alerta de Costes — ${data.month}</b>\n\n`;
message += `Total: €${data.total_spent} / €${data.total_cap} (${data.total_pct}%)\n\n`;

for (const alert of alerts) {
  message += `${alert.level} <b>${alert.tool}</b>: €${alert.spent} / €${alert.cap} (${alert.pct}%)\n`;
}

message += `\n📊 Evaluado: ${new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })}`;

return [{ json: { message, alerts_count: alerts.length } }];

